var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐이잉… 니콜…","JPN":"ふえーん……ニコル……","ENG":"Hnnggg... Nicole...","TWN":"嗚嗚嗚…妮可…"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? …와앗!","JPN":"はい？　……わっ！","ENG":"Yes? *Gasp!*","TWN":"嗯？…怎麼搞的！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"머리에 그 엄청난 혹은 뭐죠?","JPN":"その頭の大きなこぶはどうしたんですか？","ENG":"What's that gigantic bump on your head?","TWN":"你頭上腫一大包是怎麼回事？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"옷도 흙투성이에다가……","JPN":"服も泥だらけで……","ENG":"Your clothes are covered with dirt, too.","TWN":"衣服上也都是泥土……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"설마 전에 괴롭혔던 사람들이 다시 나타난 건가요?","JPN":"まさか、この前の不良たちがまた現れたんですか？","ENG":"Oh no, were you bullied by the people from before again?","TWN":"該不會是之前找你麻煩的小混混又出現啦？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"힉… 밖에 놀러 나갔다가… 끅… 화분… 머리에… 떨어져서… 히끅….","JPN":"ひっく……外に遊びに行ったら……ひっく……\\n植木鉢が……落ちてきて……頭に……ひっく……","ENG":"*Hiccups!* I went outside to play... *Hiccups!* And a flowerpot... dropped on my head... Boohoo!","TWN":"嗚…人家在外面玩…突然…就有一個盆栽…掉到…人家頭上…嗚嗚…"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"화분?! 그거 괜찮은 거예요?!","JPN":"植木鉢が頭に！？　大丈夫ですか！","ENG":"A flowerpot? Are you okay?","TWN":"盆栽？那盆栽沒事吧？！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼 이럴 때가 아니라 얼른 병원에 가야죠!","JPN":"こうしている場合じゃありません！　はやく病院に行かないと！","ENG":"We shouldn't be here. Come on, let's go to the hospital!","TWN":"現在不是關心盆栽的時候，快去醫院吧！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"괜찮아… 히끅… 대신 맛있는 거 만들어줘.","JPN":"大丈夫……ひっく……かわりにおいしいもの作って。","ENG":"I'm fine... *Hiccups!* But make me something delicious...","TWN":"不用啦…嗚嗚…你做好吃的給我就好。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아니, 그런 소리 할 때가 아니잖아요!","JPN":"いや、そんなことを言ってる場合じゃないです！","ENG":"What? How can you think about food right now?","TWN":"什麼？現在不是討吃的時候吧！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이런 와중에도 먹을 거 타령하는 걸 보면 충격으로 머리에 이상이 생긴 게 분명해!","JPN":"こんな状態なのに食べ物の話をする時点で、\\n衝撃で頭に異常が生じたに違いません！","ENG":"There's no way you're thinking about that unless you've had a concussion.","TWN":"這種時候還吵著要吃東西，看來是因為頭腦受到撞擊，導致行為異常！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"당장 병원으로 가죠!","JPN":"今すぐ病院に行きましょう！","ENG":"I'm taking you to the hospital!","TWN":"我們趕快去醫院！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"엑스레이 촬영을 해 봤지만, 별다른 외상은 발견되지 않네요.","JPN":"レントゲンを撮ってみましたが、これといった外傷は見つかりませんね。","ENG":"We did some X-rays, but didn't find any serious internal injuries.","TWN":"我們已經替她照過X光，沒發現什麼外傷。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"혹도 걱정하신 것만큼 그렇게 심하진 않고요.","JPN":"頭のこぶも心配されるほどひどくはありません。","ENG":"Her bump isn't as bad as it looks, either.","TWN":"傷勢應該沒有你想得那麼嚴重。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 하지만 화분에 맞은 건데요? 여기 오기 전까지만 해도 혹이 주먹만 했는데요? 정말로 괜찮은 건가요?","JPN":"本当ですか？　でも植木鉢が当たったんですよ？\\nここに来る前までこぶだって拳くらいの大きさでしたよ？　本当に大丈夫なんですか？","ENG":"Really? But she got hit by a flowerpot. It was as big as my fist before we got here. Are you sure she'll be okay?","TWN":"什麼？她是被盆栽砸到欸？在到醫院之前，她頭上還腫一大包跟拳頭一樣欸？真的沒事嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"하하, 괜찮습니다. 몇 번 병원에 와서 진찰만 받으면 당장은 큰 문제 없을 거예요.","JPN":"ハハ、心配ありません。\\nあと数回病院に来てもらって診察すれば、大きな問題はないでしょう。","ENG":"Hah hah, yes, I'm sure. Just bring her here a couple of more times for a quick checkup, and she'll be fine.","TWN":"哈哈，沒事啦，只要來醫院回診幾次就好，應該是沒什麼大礙。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};